IMGUI_CHECKVERSION();
ImGui::CreateContext();
ImGuiIO& io = ImGui::GetIO();
io.ConfigFlags |= ImGuiConfigFlags_DockingEnable;

PlatformBackend_Init(...);
RendererBackend_Init(...);

while (application_running) {
 PlatformBackend_ProcessEvents(...);
 RendererBackend_NewFrame();
 PlatformBackend_NewFrame();
 ImGui::NewFrame();

 ImGui::Begin("Main Tools");
 ImGui::Text("Dear ImGui is ready");
 ImGui::End();

 ImGui::Render();
 RendererBackend_RenderDrawData(ImGui::GetDrawData());
}

RendererBackend_Shutdown();
PlatformBackend_Shutdown();
ImGui::DestroyContext();
